import React, { createContext, useState, useEffect } from 'react';

export const AppContext = createContext();

export const AppProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);

  // READ - Получить все кроссовки
  const fetchProducts = async () => {
    const res = await fetch('http://localhost:3001/products');
    setProducts(await res.json());
  };

  // CREATE - Сделать заказ (Связь 1:N)
  const createOrder = async (cart) => {
    const newOrder = {
      userId: user.id, // Привязка к юзеру
      items: cart,
      date: new Date().toLocaleString(),
      total: cart.reduce((sum, item) => sum + item.price, 0)
    };
    await fetch('http://localhost:3001/orders', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newOrder)
    });
    fetchOrders(); // Обновляем список после заказа
  };

  // READ - Получить заказы (Отношение один ко многим)
  const fetchOrders = async () => {
    if (!user) return;
    const res = await fetch(`http://localhost:3001/orders?userId=${user.id}`);
    setOrders(await res.json());
  };

  // UPDATE - Обновить товар (например, цену)
  const updateProduct = async (id, newPrice) => {
    await fetch(`http://localhost:3001/products/${id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ price: Number(newPrice) })
    });
    fetchProducts();
  };

  // DELETE - Удалить товар (из каталога)
  const deleteProduct = async (id) => {
    await fetch(`http://localhost:3001/products/${id}`, { method: 'DELETE' });
    fetchProducts();
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  return (
    <AppContext.Provider value={{ 
      user, setUser, products, orders, 
      createOrder, fetchOrders, updateProduct, deleteProduct 
    }}>
      {children}
    </AppContext.Provider>
  );
};
